3_real_world_example.code:
const p1 = Promise.resolve('Weather Data');
const p2 = Promise.reject('News API Offline');
const p3 = Promise.resolve('Stock Data');

Promise.allSettled([p1, p2, p3])
  .then(results => {
    // results is ALWAYS an array, this .then ALWAYS runs
    results.forEach((result, index) => {
      if (result.status === 'fulfilled') {
        console.log(`Task ${index} succeeded with:`, result.value);
      } else {
        console.error(`Task ${index} failed because:`, result.reason);
      }
    });

    // Output:
    // Task 0 succeeded with: Weather Data
    // Task 1 failed because: News API Offline
    // Task 2 succeeded with: Stock Data
  });

